/**
 * Simple template engine that replaces {{variable}} placeholders
 * with values from a data object.
 *
 * Uses safe property lookup instead of eval() to prevent
 * remote code execution (CWE-94).
 */
function renderTemplate(template: string, data: Record<string, unknown>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    const key = expression.trim();

    // Resolve dot-notation paths like "user.name" safely
    const value = resolvePath(data, key);

    if (value === undefined) {
      return "";
    }

    return String(value);
  });
}

/**
 * Safely resolves a dot-notation path against a data object.
 * e.g. resolvePath({ user: { name: "Alice" } }, "user.name") => "Alice"
 *
 * Only allows simple alphanumeric property access — no code execution.
 */
function resolvePath(data: Record<string, unknown>, path: string): unknown {
  // Validate that the path only contains safe characters (alphanumeric, dots, underscores, hyphens, array indices)
  if (!/^[a-zA-Z0-9_.\-\[\]]+$/.test(path)) {
    return undefined;
  }

  // Normalise bracket notation: "items[0]" -> "items.0"
  const normalised = path.replace(/\[(\d+)\]/g, ".$1");
  const parts = normalised.split(".");

  let current: unknown = data;

  for (const part of parts) {
    if (current === null || current === undefined) {
      return undefined;
    }

    if (typeof current !== "object") {
      return undefined;
    }

    // Prevent prototype pollution / access to __proto__, constructor, prototype
    if (part === "__proto__" || part === "constructor" || part === "prototype") {
      return undefined;
    }

    current = (current as Record<string, unknown>)[part];
  }

  return current;
}

// ---- Hono app example ----

import { Hono } from "hono";

const app = new Hono();

app.get("/", (c) => {
  const html = renderTemplate(
    `<html>
      <body>
        <h1>Hello, {{user.name}}!</h1>
        <p>Your role is: {{user.role}}</p>
        <p>Item count: {{itemCount}}</p>
        <p>First item: {{items[0]}}</p>
      </body>
    </html>`,
    {
      user: { name: "Alice", role: "admin" },
      itemCount: 42,
      items: ["widget", "gadget", "gizmo"],
    }
  );

  return c.html(html);
});

export { renderTemplate, resolvePath, app };
export default app;

