/**
 * Simple template engine that replaces {{variable}} placeholders
 * with values from a data object.
 * 
 * Supports dot notation for nested properties (e.g., {{user.name}}).
 * Does NOT use eval() — instead uses safe property lookup to prevent
 * remote code execution (CWE-94).
 */

import { Hono } from "hono";

function getNestedValue(obj: Record<string, unknown>, path: string): unknown {
  const keys = path.split(".");
  let current: unknown = obj;
  for (const key of keys) {
    if (current === null || current === undefined) {
      return undefined;
    }
    if (typeof current === "object" && key in (current as Record<string, unknown>)) {
      current = (current as Record<string, unknown>)[key];
    } else {
      return undefined;
    }
  }
  return current;
}

export function renderTemplate(
  template: string,
  data: Record<string, unknown>
): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    const trimmed = expression.trim();

    // Handle simple ternary-like expressions: condition ? trueVal : falseVal
    // where condition, trueVal, and falseVal are all property paths or string literals
    const ternaryMatch = trimmed.match(
      /^([a-zA-Z0-9_.]+)\s*\?\s*(.+?)\s*:\s*(.+)$/
    );
    if (ternaryMatch) {
      const conditionPath = ternaryMatch[1].trim();
      const trueBranch = ternaryMatch[2].trim();
      const falseBranch = ternaryMatch[3].trim();
      const conditionValue = getNestedValue(data, conditionPath);
      const branch = conditionValue ? trueBranch : falseBranch;
      return resolveValue(branch, data);
    }

    // Handle simple logical OR: path1 || path2
    const orMatch = trimmed.match(
      /^([a-zA-Z0-9_.]+)\s*\|\|\s*(.+)$/
    );
    if (orMatch) {
      const leftPath = orMatch[1].trim();
      const rightExpr = orMatch[2].trim();
      const leftValue = getNestedValue(data, leftPath);
      if (leftValue) {
        return String(leftValue);
      }
      return resolveValue(rightExpr, data);
    }

    // Simple property path lookup
    const value = getNestedValue(data, trimmed);
    if (value === undefined) {
      return "";
    }
    return String(value);
  });
}

/**
 * Resolve a value that could be a string literal (quoted) or a property path.
 */
function resolveValue(expr: string, data: Record<string, unknown>): string {
  // Check for string literals: 'value' or "value"
  const stringLiteralMatch = expr.match(/^(['"])(.*)(\1)$/);
  if (stringLiteralMatch) {
    return stringLiteralMatch[2];
  }

  // Otherwise treat as a property path
  const value = getNestedValue(data, expr);
  if (value === undefined) {
    return expr; // return raw text as fallback
  }
  return String(value);
}

