 * Supports:
 *  - Simple property access: "name", "user.address.city"
 *  - String concatenation with +: "firstName + ' ' + lastName"
 *  - Literal strings in single or double quotes
 */
function resolveExpression(
  expression: string,
  data: Record<string, any>
): any {
  // If the expression contains '+', treat it as a concatenation expression
  if (expression.includes("+")) {
    const parts = expression.split("+").map((part) => part.trim());
    const resolvedParts = parts.map((part) => {
      // Check if it's a string literal (single or double quoted)
      const stringLiteralMatch = part.match(/^(['"])(.*)\1$/);
      if (stringLiteralMatch) {
        return stringLiteralMatch[2];
      }
      // Check if it's a number literal
      if (!isNaN(Number(part)) && part !== "") {
        return Number(part);
      }
      // Otherwise resolve as a property path
      const val = resolvePropertyPath(part, data);
      return val !== undefined && val !== null ? val : "";
    });
    return resolvedParts.join("");
  }

  // Check if it's a string literal
  const stringLiteralMatch = expression.match(/^(['"])(.*)\1$/);
  if (stringLiteralMatch) {
    return stringLiteralMatch[2];
  }

  // Check if it's a number literal
  if (!isNaN(Number(expression)) && expression !== "") {
    return Number(expression);
  }

  // Resolve as a property path (e.g., "user.name" or "title")
  return resolvePropertyPath(expression, data);
}

/**
 * Resolves a dot-separated property path against a data object.
 * E.g., "user.address.city" -> data.user.address.city
 */
function resolvePropertyPath(
  path: string,
  data: Record<string, any>
): any {
  const keys = path.split(".");
  let current: any = data;
  for (const key of keys) {
    if (current === undefined || current === null) {
      return undefined;
