function evaluateTemplate(template: string, data: Record<string, unknown>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    // Instead of using eval(), we build a Function with fixed parameter names
    // from the data keys and call it with the corresponding values.
    // This avoids CWE-94 by not using eval() directly on dynamic strings
    // and instead using a controlled scope with only the provided data keys.

    const keys = Object.keys(data);
    const values = keys.map((k) => data[k]);

    // Sanitize: only allow expressions that reference identifiers, numbers,
    // strings, and basic arithmetic/comparison operators.
    // Reject anything that looks like code injection (function calls to
    // dangerous globals, assignments, etc.)
    const allowedPattern = /^[\w\s\+\-\*\/\%\(\)\.\,\<\>\=\!\&\|\?\:\'\"\`\[\]]+$/;
    if (!allowedPattern.test(expression.trim())) {
      return `[invalid expression: ${expression.trim()}]`;
    }

    try {
      // Create a function whose parameters are the data keys and whose body
      // returns the evaluated expression. The expression can only reference
      // the provided data fields — no access to global scope.
      const fn = new Function(...keys, `"use strict"; return (${expression.trim()});`);
      const result = fn(...values);
      return String(result);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      return `[error: ${message}]`;
    }
  });
}

