  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    // Instead of using eval(), we construct a Function with fixed parameter names
    // derived from the data keys, avoiding arbitrary code injection (CWE-94).
    const keys = Object.keys(data);
