      'import', 'require', 'eval', 'Function', 'constructor',
      'prototype', '__proto__', 'process', 'global', 'window',
      'document', 'fetch', 'XMLHttpRequest', 'exec', 'spawn',
      'child_process', 'setTimeout', 'setInterval', 'setImmediate',
    ];
