function evaluateTemplate(template: string, data: Record<string, any>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    // Instead of using eval(), we build a Function with fixed parameter names
    // from the data keys and call it with the corresponding values.
    // This avoids arbitrary code injection (CWE-94).
    const keys = Object.keys(data);
    const values = keys.map((k) => data[k]);

    // Construct a function that exposes each data key as a local variable
    // and returns the result of the expression.
    // We use JSON.parse(JSON.stringify(...)) to sanitize the key names,
    // ensuring they are valid identifiers (no code injection through keys).
    const safeKeys = keys.map((k) => {
      // Only allow valid JS identifiers as parameter names
      if (!/^[a-zA-Z_$][a-zA-Z0-9_$]*$/.test(k)) {
        throw new Error(`Invalid identifier in data key: "${k}"`);
      }
      return k;
    });

    // Only allow a restricted set of characters in expressions:
    // identifiers, digits, whitespace, arithmetic operators, parentheses, dots, commas
    const trimmedExpr = expression.trim();
    if (!/^[a-zA-Z0-9_$\s\+\-\*\/\%\(\)\.\,\?\:><\=\!\&\|]+$/.test(trimmedExpr)) {
      throw new Error(`Disallowed characters in expression: "${trimmedExpr}"`);
    }

    // Disallow dangerous patterns: function calls to constructors, assignment, etc.
    // We allow only simple property access and arithmetic/logical operations.
    const dangerous =
      /\b(function|=>|new |import |require|eval|constructor|prototype|__proto__|globalThis|window|process)\b/;
    if (dangerous.test(trimmedExpr)) {
      throw new Error(`Disallowed keyword in expression: "${trimmedExpr}"`);
    }

    try {
      // Using Function constructor with fixed, validated parameter names
      // and a restricted expression – safer than eval()
      const fn = new Function(...safeKeys, `"use strict"; return (${trimmedExpr});`);
      const result = fn(...values);
      return result != null ? String(result) : "";
    } catch (err: any) {
      return `[Error: ${err.message}]`;
    }
  });
}

