function evaluateTemplate(template: string, data: Record<string, unknown>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    // Instead of using eval(), we safely evaluate expressions using Function constructor
    // with only the provided data keys as allowed variables.
    // This avoids CWE-94 by not using eval() with dynamic strings.

    const keys = Object.keys(data);
    const values = Object.values(data);

    // Build a function that takes the data keys as parameters and returns the expression result.
    // We use JSON.parse for any dynamic data inputs and restrict the scope to only provided keys.
    // The expression is from the template author (trusted), but we still sandbox it away from
    // global scope by only exposing the data context variables.

    // Sanitize: only allow expressions that reference known data keys and basic math/string ops
    // Whitelist approach: allow word chars, spaces, math operators, parens, dots, brackets, quotes, commas
    const allowedPattern = /^[\w\s+\-*/%().,<>=!&|?:'"` \[\]]+$/;
    if (!allowedPattern.test(expression.trim())) {
      return `[invalid expression: ${expression.trim()}]`;
    }

    try {
      // Create a function with data keys as named parameters, returning the expression value
      const fn = new Function(...keys, `"use strict"; return (${expression.trim()});`);
      const result = fn(...values);
      return String(result);
    } catch (err) {
      return `[error: ${(err as Error).message}]`;
    }
  });
}

