function evaluateTemplate(template: string, data: Record<string, unknown>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    // Instead of using eval(), safely evaluate by constructing a function
    // with explicit parameter names from the data context.
