    const safeValues = keys.map(k => {
      const v = data[k];
      // Round-trip through JSON.parse to ensure data is plain data, not executable
      return JSON.parse(JSON.stringify(v));
    });

    try {
      // Create a function whose only in-scope variables are the data keys.
      // This is significantly safer than eval() as it cannot access
      // the surrounding scope, globals like require/process/etc.
      const fn = new Function(...keys, `"use strict"; return (${expression});`);
      const result = fn(...safeValues);
      return String(result);
    } catch (err) {
      return `[Error: ${(err as Error).message}]`;
